// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  city: string; // City name
  temperature: number; // Current temperature
  condition: string; // Weather condition (Sunny, Cloudy, Rainy, etc.)
  humidity: number; // Humidity percentage
  windSpeed: number; // Wind speed
  unit: string; // Temperature unit (C or F)
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>; // 5-day forecast array
}





function getConditionGlyph(condition: string): string {
  const value = condition.toLowerCase();
  if (value.includes('rain') || value.includes('drizzle') || value.includes('shower')) return '🌧️';
  if (value.includes('snow') || value.includes('sleet') || value.includes('flurr')) return '❄️';
  if (value.includes('storm') || value.includes('thunder')) return '⛈️';
  if (value.includes('cloud') || value.includes('overcast') || value.includes('fog') || value.includes('mist') || value.includes('haze')) return '☁️';
  if (value.includes('wind')) return '💨';
  if (value.includes('clear') || value.includes('sun') || value.includes('bright')) return '☀️';
  return '🌡️';
}

function getForecastGlyph(icon: string | undefined, day?: string): string {
  const source = `${icon ?? ''} ${day ?? ''}`.toLowerCase();
  if (source.includes('rain') || source.includes('drizzle') || source.includes('shower')) return '🌧️';
  if (source.includes('snow') || source.includes('sleet') || source.includes('flurr')) return '❄️';
  if (source.includes('storm') || source.includes('thunder')) return '⛈️';
  if (source.includes('cloud') || source.includes('overcast') || source.includes('fog') || source.includes('mist') || source.includes('haze')) return '☁️';
  if (source.includes('wind')) return '💨';
  if (source.includes('clear') || source.includes('sun')) return '☀️';
  return icon?.trim() ? icon : '🌤️';
}

function formatTemp(value: number | undefined, unit: string): string {
  if (typeof value !== 'number' || Number.isNaN(value)) return '—';
  return `${Math.round(value)}°${unit || ''}`;
}

function formatPercent(value: number): string {
  return `${Math.round(value)}%`;
}

function formatWind(value: number): string {
  return `${Math.round(value)} wind units`;
}

function isForecastItemValid(item: { day?: string; icon?: string; high?: number; low?: number }): boolean {
  return Boolean(item && (item.day || item.icon || typeof item.high === 'number' || typeof item.low === 'number'));
}

function getDayLabel(day?: string, index?: number): string {
  if (day && day.trim()) return day;
  return index !== undefined ? `Day ${index + 1}` : 'Day';
}

function getForecastCardStyle(index: number): React.CSSProperties {
  return {
    minWidth: '0',
    flex: '1 1 0',
    animationDelay: `${index * 40}ms`,
  };
}

export default function Component(props: Props) {
  const forecast = useMemo(() => (Array.isArray(props.forecast) ? props.forecast : []), [props.forecast]);
  const displayForecast = useMemo(() => forecast.slice(0, 5), [forecast]);
  const hasForecast = displayForecast.length > 0;
  const isForecastLongEnough = displayForecast.length >= 5;
  const weatherGlyph = useMemo(() => getConditionGlyph(props.condition), [props.condition]);
  const unitLabel = props.unit || '';
  const windValue = formatWind(props.windSpeed);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Card padding="var(--ggui-spacing-6)" shadow="md" radius="xl">
        <Stack gap="var(--ggui-spacing-6)">
          <Box
            padding="var(--ggui-spacing-6)"
            background="var(--ggui-color-container)"
            borderRadius="var(--ggui-shape-radius-xl)"
          >
            <Stack gap="var(--ggui-spacing-4)">
              <Row align="center" justify="between" wrap>
                <Stack gap="var(--ggui-spacing-1)">
                  <Text variant="overline" color="var(--ggui-color-onContainer)">
                    Current weather
                  </Text>
                  <Heading level={2} color="var(--ggui-color-onContainer)">
                    {props.city}
                  </Heading>
                  <Text variant="bodyLarge" color="var(--ggui-color-onContainer)">
                    {props.condition}
                  </Text>
                </Stack>
                <Row align="center" gap="var(--ggui-spacing-3)">
                  <Text as="span" size="4xl" weight="bold" color="var(--ggui-color-onContainer)">
                    {weatherGlyph}
                  </Text>
                  <Stack gap="0" align="end">
                    <Heading level={1} color="var(--ggui-color-onContainer)">
                      {formatTemp(props.temperature, unitLabel)}
                    </Heading>
                    <Text variant="caption" color="var(--ggui-color-onContainer)">
                      Humidity {formatPercent(props.humidity)} · Wind {windValue}
                    </Text>
                  </Stack>
                </Row>
              </Row>

              <Row gap="var(--ggui-spacing-3)" wrap>
                <Badge variant="secondary" size="lg">
                  Humidity {formatPercent(props.humidity)}
                </Badge>
                <Badge variant="secondary" size="lg">
                  Wind {windValue}
                </Badge>
                <Badge variant="primary" size="lg">
                  {props.condition}
                </Badge>
              </Row>
            </Stack>
          </Box>

          <Card padding="var(--ggui-spacing-4)" shadow="none" border radius="lg">
            <Stack gap="var(--ggui-spacing-3)">
              <Row align="center" justify="between" wrap>
                <Stack gap="var(--ggui-spacing-1)">
                  <Heading level={4}>5-day forecast</Heading>
                  <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                    Five-day outlook at a glance.
                  </Text>
                </Stack>
                {hasForecast && (
                  <Badge variant={isForecastLongEnough ? 'success' : 'warning'} size="md">
                    {displayForecast.length}/5 days
                  </Badge>
                )}
              </Row>

              {hasForecast ? (
                <Box padding="var(--ggui-spacing-3)" background="var(--ggui-color-surfaceVariant)" borderRadius="var(--ggui-shape-radius-lg)">
                  <Row gap="var(--ggui-spacing-2)" wrap>
                    {displayForecast.map((item, index) => (
                      <Card
                        key={`${item.day ?? index}-${index}`}
                        padding="var(--ggui-spacing-3)"
                        shadow="none"
                        border
                        radius="md"
                        style={getForecastCardStyle(index)}
                      >
                        <Stack gap="var(--ggui-spacing-2)" align="center">
                          <Text variant="label" align="center">
                            {getDayLabel(item.day, index)}
                          </Text>
                          <Text as="span" size="2xl">
                            {getForecastGlyph(item.icon, item.day)}
                          </Text>
                          <Text variant="bodySmall" align="center">
                            {formatTemp(item.high, unitLabel)} / {formatTemp(item.low, unitLabel)}
                          </Text>
                        </Stack>
                      </Card>
                    ))}
                  </Row>
                </Box>
              ) : (
                <Alert variant="info" title="No forecast available">
                  Forecast data was not provided.
                </Alert>
              )}
            </Stack>
          </Card>
        </Stack>
      </Card>
    </Container>
  );
}

