import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  featureOptions: string[]; // Available feature options for the checkbox step
  satisfactionLabels: string[]; // Labels for satisfaction rating (e.g., Very Unsatisfied to Very Satisfied)
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all collected answers as a structured object */
type ActionSubmitPayload = { name: string; email: string; satisfaction: number; features: string[]; comments: string };





type ReviewItem = { label: string; value: React.ReactNode };

const defaultRatingLabels = ['Very Unsatisfied', 'Unsatisfied', 'Neutral', 'Satisfied', 'Very Satisfied'];

const isEmail = (value: string) => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(value.trim());

const getRatingOptions = (labels: string[]) =>
  (labels && labels.length ? labels : defaultRatingLabels).slice(0, 5).map((label, index) => ({
    value: String(index + 1),
    label,
  }));

const ReviewList = (props: { items?: ReviewItem[] }) => (
  <Stack gap="var(--ggui-spacing-3)">
    {(props.items ?? []).map((item) => (
      <Row key={item.label} gap="var(--ggui-spacing-3)" align="start">
        <Text variant="bodySmall" weight="semibold" color="var(--ggui-color-onSurfaceVariant)" style={{ minWidth: '140px' } as React.CSSProperties}>
          {item.label}
        </Text>
        <Text variant="bodySmall" color="var(--ggui-color-onSurface)">
          {item.value}
        </Text>
      </Row>
    ))}
  </Stack>
);

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const submit = useAction<ActionSubmitPayload>('submit');

  const [step, setStep] = useState(1);
  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [satisfaction, setSatisfaction] = useState('');
  const [features, setFeatures] = useState<string[]>([]);
  const [comments, setComments] = useState('');
  const [touched, setTouched] = useState({ name: false, email: false });
  const ratingOptions = useMemo(() => getRatingOptions(props.satisfactionLabels), [props.satisfactionLabels]);
  const nameError = touched.name && !name.trim() ? 'Name is required.' : '';
  const emailError = touched.email && !email.trim() ? 'Email is required.' : touched.email && !isEmail(email) ? 'Enter a valid email address.' : '';
  const canGoNext = step === 1 ? !!name.trim() && isEmail(email) : step === 2 ? !!satisfaction : true;
  const currentRating = Number(satisfaction || '0');
  const reviewItems: ReviewItem[] = [
    { label: 'Name', value: name.trim() || '—' },
    { label: 'Email', value: email.trim() || '—' },
    { label: 'Satisfaction', value: currentRating ? `${currentRating} / 5` : '—' },
    { label: 'Features', value: features.length ? features.join(', ') : 'None selected' },
    { label: 'Comments', value: comments.trim() || 'No comments' },
  ];

  const handleNext = useCallback(() => {
    if (step === 1) setTouched({ name: true, email: true });
    if (step === 1 && (!name.trim() || !isEmail(email))) return;
    if (step === 2 && !satisfaction) return;
    setStep((current) => Math.min(4, current + 1));
  }, [step, name, email, satisfaction]);

  const handleBack = useCallback(() => setStep((current) => Math.max(1, current - 1)), []);

  const toggleFeature = useCallback((feature: string) => {
    setFeatures((current) => current.includes(feature) ? current.filter((item) => item !== feature) : [...current, feature]);
  }, []);

  const handleSubmit = useCallback(() => {
    submit({
      name: name.trim(),
      email: email.trim(),
      satisfaction: Number(satisfaction),
      features,
      comments: comments.slice(0, 500),
    });
  }, [submit, name, email, satisfaction, features, comments]);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        <Card padding="var(--ggui-spacing-6)" shadow="md">
          <Stack gap="var(--ggui-spacing-4)">
            <Row justify="between" align="center">
              <Heading level={2}>Multi-step Survey</Heading>
              <Badge variant="primary">Step {Math.min(step, 4)} of 4</Badge>
            </Row>
            <Progress value={Math.min(step, 4) * 25} max={100} showLabel />

            {step === 1 ? (
              <Stack gap="var(--ggui-spacing-4)">
                <Input label="Name" required value={name} onChange={(value) => { setName(value); if (!touched.name) setTouched((current) => ({ ...current, name: true })); }} placeholder="Enter your name" error={nameError} helperText="Please provide your full name." />
                <Input label="Email" type="email" required value={email} onChange={(value) => { setEmail(value); if (!touched.email) setTouched((current) => ({ ...current, email: true })); }} placeholder="you@example.com" error={emailError} helperText="We will use this to contact you if needed." />
              </Stack>
            ) : null}

            {step === 2 ? (
              <RadioGroup label="How satisfied are you?" value={satisfaction} onChange={setSatisfaction} options={ratingOptions} />
            ) : null}

            {step === 3 ? (
              <Stack gap="var(--ggui-spacing-3)">
                <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Select all feature areas that interest you</Text>
                <Stack gap="var(--ggui-spacing-2)">
                  {props.featureOptions.map((feature) => (
                    <Checkbox key={feature} label={feature} checked={features.includes(feature)} onChange={() => toggleFeature(feature)} />
                  ))}
                </Stack>
              </Stack>
            ) : null}

            {step === 4 ? (
              <Stack gap="var(--ggui-spacing-4)">
                <Alert variant="info" title="Review your responses">Please confirm everything below before submitting.</Alert>
                <ReviewList items={reviewItems} />
                <Row justify="between" align="center">
                  <Button variant="outline" onPress={handleBack} disabled={step === 1}>Back</Button>
                  <Button variant="primary" onPress={handleSubmit}>Submit</Button>
                </Row>
              </Stack>
            ) : null}

          </Stack>
        </Card>

        <Card padding="var(--ggui-spacing-5)" shadow="sm">
          <Stack gap="var(--ggui-spacing-3)">
            <Heading level={4}>Current answers</Heading>
            <ReviewList items={reviewItems} />
          </Stack>
        </Card>
      </Stack>
    </Container>
  );
}

