import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction, useStream } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  tasks: Array<{ id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string }>; // Array of tasks with id, title, priority (low/medium/high), assignee initials, column ID, and optional dueDate
  columns: Array<{ id?: string; name?: string }>; // Column definitions: [{id: "todo", name: "To Do"}, {id: "in-progress", name: "In Progress"}, {id: "done", name: "Done"}]
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when a task is moved, edited, or created. Payload: { action, taskId, data } */
type ActionTaskUpdatePayload = { action: string; taskId: string; data: { column: string } };


// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: A task was moved, edited, or created by another user — update it in the board */
type StreamTaskChanged = { action?: 'create' | 'move' | 'edit' | 'delete'; task?: { id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string } };




type BoardTask = {
  id: string;
export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
  priority: 'low' | 'medium' | 'high';
  assignee: string;
  column: string;
  dueDate: string;
};

const COLUMN_FALLBACKS = ['todo', 'in-progress', 'done'];

const PRIORITY_OPTIONS = [
  { value: 'low', label: 'Low' },
  { value: 'medium', label: 'Medium' },
  { value: 'high', label: 'High' },
];

const PRIORITY_VARIANT: Record<string, 'default' | 'success' | 'warning' | 'error'> = {
  low: 'success',
  medium: 'warning',
  high: 'error',
};

function normalizeColumnId(id: string | undefined, index: number) {
  const fallback = COLUMN_FALLBACKS[index] ?? `column-${index + 1}`;
  return (id || fallback).toLowerCase();
}

function normalizeColumnName(name: string | undefined, id: string, index: number) {
  if (name && name.trim()) return name;
  if (id === 'todo') return 'To Do';
  if (id === 'in-progress') return 'In Progress';
  if (id === 'done') return 'Done';
  return `Column ${index + 1}`;
}

function normalizeTask(task: Props['tasks'][number], index: number): BoardTask {
  return {
    id: task.id || `task-${index}-${task.title || 'item'}`,
    title: task.title || 'Untitled task',
    priority: task.priority || 'medium',
    assignee: task.assignee || '',
    column: (task.column || COLUMN_FALLBACKS[0]).toLowerCase(),
    dueDate: task.dueDate || '',
  };
}

function getInitials(name: string) {
  const parts = name.trim().split(/\s+/).filter(Boolean);
  const initials = parts.slice(0, 2).map((part) => part[0]).join('');
  return (initials || name.slice(0, 2) || '?').toUpperCase();
}

function formatDueDate(value: string) {
  if (!value) return '';
  const date = new Date(value);
  if (Number.isNaN(date.getTime())) return value;
  return date.toLocaleDateString(undefined, { month: 'short', day: 'numeric' });
}

function TaskCard(props: {
  task: BoardTask;
  columns: Array<{ id: string; name: string }>;
  onMove: (taskId: string, columnId: string) => void;
  onEdit: (taskId: string, title: string) => void;
}) {
  const [isEditing, setIsEditing] = useState(false);
  const [draftTitle, setDraftTitle] = useState(props.task.title);

  useEffect(() => {
    setDraftTitle(props.task.title);
  }, [props.task.title]);

  const moveOptions = useMemo(() => {
    return props.columns
      .filter((column) => column.id !== props.task.column)
      .map((column) => ({ value: column.id, label: column.name }));
  }, [props.columns, props.task.column]);

  const saveEdit = useCallback(() => {
    const nextTitle = draftTitle.trim() || 'Untitled task';
    props.onEdit(props.task.id, nextTitle);
    setIsEditing(false);
  }, [draftTitle, props]);

  return (
    <Card padding="var(--ggui-spacing-4)" shadow="sm" radius="md">
      <Stack gap="var(--ggui-spacing-3)">
        <Row align="center" gap="var(--ggui-spacing-2)">
          <Badge variant={PRIORITY_VARIANT[props.task.priority]} size="sm">
            {props.task.priority}
          </Badge>
          <Spacer size="flex" />
          <Dropdown
            trigger={<Button variant="ghost" size="sm">Move</Button>}
            value={props.task.column}
            onChange={(value) => props.onMove(props.task.id, value)}
            options={moveOptions}
          />
        </Row>
        {isEditing ? (
          <Stack gap="var(--ggui-spacing-2)">
            <Input
              label="Task title"
              value={draftTitle}
              onChange={setDraftTitle}
              size="sm"
            />
            <Row gap="var(--ggui-spacing-2)">
              <Button variant="primary" size="sm" onClick={saveEdit}>Save</Button>
              <Button variant="ghost" size="sm" onClick={() => setIsEditing(false)}>Cancel</Button>
            </Row>
          </Stack>
        ) : (
          <Stack gap="var(--ggui-spacing-1)">
            <Text
              variant="bodyLarge"
              weight="semibold"
              as={Clickable}
              onClick={() => setIsEditing(true)}
              color="var(--ggui-color-onSurface)"
            >
              {props.task.title}
            </Text>
            <Button variant="ghost" size="xs" onClick={() => setIsEditing(true)}>Edit</Button>
          </Stack>
        )}
        <Row align="center" gap="var(--ggui-spacing-2)">
          <Avatar name={props.task.assignee || 'Unassigned'} size="sm" />
          <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
            {props.task.assignee || 'Unassigned'}
          </Text>
          <Spacer size="flex" />
          {props.task.dueDate ? (
            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
              Due {formatDueDate(props.task.dueDate)}
            </Text>
          ) : null}
        </Row>
      </Stack>
    </Card>
  );
}

