import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  elements: Array<{ atomicNumber?: number; symbol?: string; name?: string; atomicWeight?: number; category?: string; row?: number; col?: number }>; // Full periodic table element data
}

type ElementItem = NonNullable<Props['elements']>[number];

const CATEGORY_TOKENS: Record<string, { bg: string; fg: string; border: string }> = {
  'alkali-metal': { bg: 'var(--ggui-color-warning-50)', fg: 'var(--ggui-color-warning-800)', border: 'var(--ggui-color-warning-200)' },
  'alkaline-earth-metal': { bg: 'var(--ggui-color-warning-100)', fg: 'var(--ggui-color-warning-800)', border: 'var(--ggui-color-warning-200)' },
  'transition-metal': { bg: 'var(--ggui-color-primary-50)', fg: 'var(--ggui-color-primary-800)', border: 'var(--ggui-color-primary-200)' },
  'post-transition-metal': { bg: 'var(--ggui-color-info-50)', fg: 'var(--ggui-color-info-800)', border: 'var(--ggui-color-info-200)' },
  metalloid: { bg: 'var(--ggui-color-success-50)', fg: 'var(--ggui-color-success-800)', border: 'var(--ggui-color-success-200)' },
  nonmetal: { bg: 'var(--ggui-color-success-100)', fg: 'var(--ggui-color-success-800)', border: 'var(--ggui-color-success-200)' },
  halogen: { bg: 'var(--ggui-color-error-50)', fg: 'var(--ggui-color-error-800)', border: 'var(--ggui-color-error-200)' },
  'noble-gas': { bg: 'var(--ggui-color-primary-100)', fg: 'var(--ggui-color-primary-800)', border: 'var(--ggui-color-primary-300)' },
  lanthanide: { bg: 'var(--ggui-color-warning-100)', fg: 'var(--ggui-color-warning-800)', border: 'var(--ggui-color-warning-300)' },
  actinide: { bg: 'var(--ggui-color-error-100)', fg: 'var(--ggui-color-error-800)', border: 'var(--ggui-color-error-300)' },
  'unknown': { bg: 'var(--ggui-color-surfaceVariant)', fg: 'var(--ggui-color-onSurfaceVariant)', border: 'var(--ggui-color-outline)' },
};

function getCategoryStyle(category?: string) {
  const key = (category || 'unknown').toLowerCase();
  return CATEGORY_TOKENS[key] || CATEGORY_TOKENS['unknown'];
}

function formatValue(value?: number) {
  return typeof value === 'number' ? String(value) : '—';
}

function ElementCell(props: { element: ElementItem; selected: boolean; onSelect: (element: ElementItem) => void; }) {
  const style = getCategoryStyle(props.element.category);
  return (
    <Card
      as={Clickable}
      onClick={() => props.onSelect(props.element)}
      padding="var(--ggui-spacing-3)"
      shadow={props.selected ? 'md' : 'sm'}
      radius="md"
      border
      hoverStyle={{ opacity: 0.92 }}
      style={{
        gridRow: props.element.row ? String(props.element.row) : undefined,
        gridColumn: props.element.col ? String(props.element.col) : undefined,
        minHeight: '88px',
        background: style.bg,
        borderColor: props.selected ? 'var(--ggui-color-primary-600)' : style.border,
        outline: props.selected ? '2px solid var(--ggui-color-primary-600)' : 'none',
        outlineOffset: '2px',
      } as React.CSSProperties}
      aria-pressed={props.selected}
      aria-label={`${props.element.name || 'Element'} ${formatValue(props.element.atomicNumber)}`}
    >
      <Stack gap="var(--ggui-spacing-1)" style={{ height: '100%', justifyContent: 'space-between' } as React.CSSProperties}>
        <Text variant="caption" color={style.fg} weight="semibold" is="span">
          {formatValue(props.element.atomicNumber)}
        </Text>
        <Stack gap="0" align="center" justify="center" style={{ flex: 1 }}>
          <Heading level={3} color={style.fg} align="center">
            {props.element.symbol || '—'}
          </Heading>
        </Stack>
        <Text variant="caption" color={style.fg} align="center" truncate>
          {props.element.name || 'Unknown'}
        </Text>
      </Stack>
    </Card>
  );
}

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
  const [query, setQuery] = useState('');
  const [selected, setSelected] = useState<ElementItem | null>(null);
  const lastSelectedId = useRef<number | string | null>(null);

  const elements = props.elements || [];

  useEffect(() => {
    if (!selected && elements.length > 0) {
      setSelected(elements[0]);
    }
  }, [elements, selected]);

  useEffect(() => {
    if (selected && !elements.some((el) => el.atomicNumber === selected.atomicNumber)) {
      setSelected(elements[0] || null);
    }
  }, [elements, selected]);

  const normalizedElements = useMemo(() => {
    return elements.map((element) => ({
      ...element,
      row: element.row ?? 0,
      col: element.col ?? 0,
    }));
  }, [elements]);

  const filteredElements = useMemo(() => {
    const term = query.trim().toLowerCase();
    if (!term) return normalizedElements;
    return normalizedElements.filter((element) => {
      const name = (element.name || '').toLowerCase();
      const symbol = (element.symbol || '').toLowerCase();
      return name.includes(term) || symbol.includes(term);
    });
  }, [normalizedElements, query]);

  const categories = useMemo(() => {
    const map = new Map<string, { label: string; count: number }>();
    elements.forEach((element) => {
      const category = element.category || 'unknown';
      const label = category
        .replace(/[-_]/g, ' ')
        .replace(/\b\w/g, (m) => m.toUpperCase());
      const current = map.get(category);
      map.set(category, { label, count: (current?.count || 0) + 1 });
    });
    return Array.from(map.entries()).map(([key, value]) => ({ key, ...value }));
  }, [elements]);

  const handleSelect = useCallback((element: ElementItem) => {
    lastSelectedId.current = element.atomicNumber || element.symbol || null;
    setSelected(element);
  }, []);

  const selectedElement = selected || filteredElements[0] || elements[0] || null;
  const selectedKey = selectedElement ? `${selectedElement.atomicNumber || ''}-${selectedElement.symbol || ''}-${selectedElement.name || ''}` : '';
  const statusText = query.trim() ? `${filteredElements.length} matching elements` : `${elements.length} elements`;

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        <Card padding="var(--ggui-spacing-6)" shadow="md">
          <Stack gap="var(--ggui-spacing-4)">
            <Stack gap="var(--ggui-spacing-2)">
              <Heading level={1}>Periodic Table of Elements</Heading>
              <Text color="var(--ggui-color-onSurfaceVariant)">Search by name or symbol, then select an element to inspect its details.</Text>
            </Stack>
            <SearchField
              value={query}
              onChange={setQuery}
              placeholder="Search elements by name or symbol..."
            />
            <Row gap="var(--ggui-spacing-3)" align="center" wrap>
              <Badge variant="primary">{statusText}</Badge>
              <Badge variant="secondary">{elements.length} total</Badge>
            </Row>
          </Stack>
        </Card>

        <Card padding="var(--ggui-spacing-6)" shadow="sm">
          <Stack gap="var(--ggui-spacing-4)">
            <Row justify="between" align="center">
              <Heading level={2}>Table</Heading>
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">18-column grid layout</Text>
            </Row>
            <Box
              style={{
                display: 'grid',
                gridTemplateColumns: 'repeat(18, minmax(0, 1fr))',
                gap: 'var(--ggui-spacing-2)',
                alignItems: 'stretch',
              } as React.CSSProperties}
            >
              {filteredElements.map((element) => (
                <ElementCell
                  key={`${element.atomicNumber || element.symbol || element.name}`}`
                  element={element}
                  selected={selectedKey === `${element.atomicNumber || ''}-${element.symbol || ''}-${element.name || ''}` || (selectedElement?.atomicNumber === element.atomicNumber && selectedElement?.symbol === element.symbol)}
                  onSelect={handleSelect}
                />
              ))}
              {filteredElements.length === 0 && (
                <Alert variant="info" title="No elements found">
                  Try a different search term.
                </Alert>
              )}
            </Box>
          </Stack>
        </Card>


        <Card padding="var(--ggui-spacing-6)" shadow="sm">
          <Stack gap="var(--ggui-spacing-4)">
            <Heading level={2}>Selected element</Heading>
            {selectedElement ? (
              <Row gap="var(--ggui-spacing-6)" wrap align="start">
                <Box
                  style={{
                    minWidth: '120px',
                    flexShrink: 0,
                  } as React.CSSProperties}
                >
                  <Card padding="var(--ggui-spacing-4)" shadow="none" border style={{ background: getCategoryStyle(selectedElement.category).bg, borderColor: getCategoryStyle(selectedElement.category).border } as React.CSSProperties}>
                    <Stack gap="var(--ggui-spacing-2)" align="center">
                      <Text variant="caption" color={getCategoryStyle(selectedElement.category).fg}>
                        {formatValue(selectedElement.atomicNumber)}
                      </Text>
                      <Heading level={2} color={getCategoryStyle(selectedElement.category).fg} align="center">
                        {selectedElement.symbol || '—'}
                      </Heading>
                      <Text variant="caption" color={getCategoryStyle(selectedElement.category).fg} align="center">
                        {selectedElement.name || 'Unknown'}
                      </Text>
                    </Stack>
                  </Card>
                </Box>
                <Stack gap="var(--ggui-spacing-2)" style={{ flex: 1 }}>
                  <Row gap="var(--ggui-spacing-2)" wrap>
                    <Badge variant="secondary">Atomic Number: {formatValue(selectedElement.atomicNumber)}</Badge>
                    <Badge variant="secondary">Atomic Weight: {formatValue(selectedElement.atomicWeight)}</Badge>
                    <Badge variant="secondary">Category: {selectedElement.category || 'unknown'}</Badge>
                  </Row>
                  <Divider margin="var(--ggui-spacing-2)" />
                  <Stack gap="var(--ggui-spacing-1)">
                    <Text><Text as="span" weight="semibold">Name:</Text> {selectedElement.name || 'Unknown'}</Text>
                    <Text><Text as="span" weight="semibold">Symbol:</Text> {selectedElement.symbol || '—'}</Text>
                    <Text><Text as="span" weight="semibold">Atomic Number:</Text> {formatValue(selectedElement.atomicNumber)}</Text>
                    <Text><Text as="span" weight="semibold">Atomic Weight:</Text> {formatValue(selectedElement.atomicWeight)}</Text>
                    <Text><Text as="span" weight="semibold">Category:</Text> {selectedElement.category || 'unknown'}</Text>
                  </Stack>
                </Stack>
              </Row>
            ) : (
              <Alert variant="warning" title="No element selected">
                Select an element to view details.
              </Alert>
            )}
          </Stack>
        </Card>
        </Card>

        <Card padding="var(--ggui-spacing-6)" shadow="sm">
          <Stack gap="var(--ggui-spacing-4)">
            <Heading level={2}>Legend</Heading>
            <Row gap="var(--ggui-spacing-2)" wrap>
              {categories.map((category) => {
                const style = getCategoryStyle(category.key);
                return (
                  <Tag key={category.key} variant="default">
                    <span style={{ display: 'inline-flex', alignItems: 'center', gap: 'var(--ggui-spacing-1)' } as React.CSSProperties}>
                      <span style={{ width: '10px', height: '10px', borderRadius: '9999px', background: style.bg, border: '1px solid var(--ggui-color-outline)' }} />
                      {category.label} ({category.count})
                    </span>
                  </Tag>
                );
              })}
            </Row>
          </Stack>
        </Card>
      </Stack>
    </Container>

  );
}

