import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  product: { id?: string; name?: string; price?: number; currency?: string; rating?: number; reviewCount?: number; stock?: number; description?: string; specifications?: unknown[]; reviews?: unknown[] }; // Product object with id, name, price, currency, rating, stock, description, specifications[], reviews[]
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when user clicks Add to Cart. Payload: { productId, quantity } */
type ActionAddToCartPayload = { productId: string; quantity: number };





function formatCurrency(amount: number | undefined, currency: string | undefined) {
  if (typeof amount !== 'number') {
    return '—';
  }
  const symbolMap: Record<string, string> = {
    USD: '$',
    EUR: '€',
    GBP: '£',
    JPY: '¥',
    CAD: 'C$',
    AUD: 'A$',
  };
  const code = (currency || '').toUpperCase();
  const symbol = symbolMap[code] || `${code} `;
  return `${symbol}${amount.toFixed(2)}`;
}

function toNumber(value: unknown, fallback = 0) {
  const parsed = typeof value === 'number' ? value : Number(value);
  return Number.isFinite(parsed) ? parsed : fallback;
}

function renderStars(rating: number | undefined) {
  const safeRating = Math.max(0, Math.min(5, Math.round(toNumber(rating, 0))));
  return Array.from({ length: 5 }, (_, index) => ({
    filled: index < safeRating,
    key: index,
  }));
}

function renderProductSpecs(specifications: unknown[] | undefined) {
  return (Array.isArray(specifications) ? specifications : [])
    .map((spec, index) => {
      if (spec && typeof spec === 'object' && !Array.isArray(spec)) {
        const entries = Object.entries(spec as Record<string, unknown>);
        if (entries.length >= 2) {
          const [key, value] = entries[0];
          return {
            key: `${key}-${index}`
              ,
            label: String(key),
            value: String(value),
          };
        }
      }
      if (Array.isArray(spec) && spec.length >= 2) {
        return {
          key: `${String(spec[0])}-${index}`,
          label: String(spec[0]),
          value: String(spec[1]),
        };
      }
      return { key: `spec-${index}`, label: `Spec ${index + 1}`, value: String(spec) };
    });
}

function renderProductReviews(reviews: unknown[] | undefined) {
  return (Array.isArray(reviews) ? reviews : []).map((review, index) => {
    const item = review && typeof review === 'object' ? (review as Record<string, unknown>) : {};
    return {
      key: String(item.id ?? index),
      author: String(item.author ?? item.name ?? 'Anonymous'),
      rating: Math.max(0, Math.min(5, Math.round(toNumber(item.rating, 0)))),
      text: String(item.text ?? item.content ?? ''),
      date: String(item.date ?? item.timestamp ?? ''),
    };
  });
}

function StarRow({ rating }: { rating: number }) {
  return (
    <Row gap="var(--ggui-spacing-1)" align="center">
      {Array.from({ length: 5 }, (_, index) => (
        <Icon
          key={index}
          name={index < rating ? 'star' : 'star'}
          size={16}
          color={index < rating ? 'var(--ggui-color-warning)' : 'var(--ggui-color-outline)'}
        />
      ))}
    </Row>
  );
}

function QuantityControl(props: { quantity: number; min: number; max: number; onDecrement: () => void; onIncrement: () => void; disabled: boolean; }) {
  return (
    <Row gap="var(--ggui-spacing-2)" align="center">
      <Button variant="outline" size="sm" disabled={props.disabled || props.quantity <= props.min} onClick={props.onDecrement}>
        −
      </Button>
      <Box paddingX="var(--ggui-spacing-4)" paddingY="var(--ggui-spacing-2)" borderRadius="var(--ggui-shape-radius-md)" background="var(--ggui-color-surfaceVariant)">
        <Text variant="label">{props.quantity}</Text>
      </Box>
      <Button variant="outline" size="sm" disabled={props.disabled || props.quantity >= props.max} onClick={props.onIncrement}>
        +
      </Button>
    </Row>
  );
}

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const addToCart = useAction<ActionAddToCartPayload>('addToCart'); // Called when user clicks Add to Cart. Payload: { productId, quantity }

  const [selectedTab, setSelectedTab] = useState('description');
  const [quantity, setQuantity] = useState(1);
  const descriptionRef = useRef<HTMLDivElement | null>(null);

  const stock = Math.max(0, toNumber(props.product.stock, 0));
  const isOutOfStock = stock <= 0;
  const isLowStock = stock > 0 && stock <= 5;
  const maxQuantity = Math.max(1, stock);

  useEffect(() => {
    setQuantity((current) => Math.min(Math.max(1, current), maxQuantity));
  }, [maxQuantity]);

  useEffect(() => {
    if (selectedTab === 'description' && descriptionRef.current) {
      descriptionRef.current.focus?.();
    }
  }, [selectedTab]);

  const stars = useMemo(() => renderStars(props.product.rating), [props.product.rating]);
  const specs = useMemo(() => renderProductSpecs(props.product.specifications), [props.product.specifications]);
  const reviews = useMemo(() => renderProductReviews(props.product.reviews), [props.product.reviews]);

  const tabs = useMemo(() => ([
    {
      key: 'description',
      label: 'Description',
      content: (
        <Box paddingY="var(--ggui-spacing-4)">
          <Text ref={descriptionRef as never} variant="body">{props.product.description || '—'}</Text>
        </Box>
      ),
    },
    {
      key: 'specifications',
      label: 'Specifications',
      content: (
        <Box paddingY="var(--ggui-spacing-4)">
          <Table
            columns={[
              { key: 'label', header: 'Specification' },
              { key: 'value', header: 'Value' },
            ]}
            data={specs}
            bordered
            caption="Product specifications"
          />
        </Box>
      ),
    },
    {
      key: 'reviews',
      label: 'Reviews',
      content: (
        <Stack gap="var(--ggui-spacing-3)">
          {reviews.length === 0 ? (
            <Text color="var(--ggui-color-onSurfaceVariant)">No reviews available.</Text>
          ) : (
            reviews.map((review) => (
              <Card key={review.key} padding="var(--ggui-spacing-4)" shadow="sm">
                <Stack gap="var(--ggui-spacing-2)">
                  <Row justify="between" align="center" wrap>
                    <Stack gap="var(--ggui-spacing-1)">
                      <Text variant="label">{review.author}</Text>
                      <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">{review.date || '—'}</Text>
                    </Stack>
                    <StarRow rating={review.rating} />
                  </Row>
                  <Text variant="bodySmall">{review.text || '—'}</Text>
                </Stack>
              </Card>
            ))
          )}
        </Stack>
      )
    }
  ]), [reviews, specs]);

  const handleAddToCart = useCallback(() => {
    if (isOutOfStock || !props.product.id) {
      return;
    }
    addToCart({ productId: props.product.id, quantity });
  }, [addToCart, isOutOfStock, props.product.id, quantity]);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        <Card padding="var(--ggui-spacing-6)" shadow="md">
          <Stack gap="var(--ggui-spacing-6)">
            <Row gap="var(--ggui-spacing-6)" wrap align="stretch">
              <Box
                padding="var(--ggui-spacing-6)"
                background="var(--ggui-color-primary-50)"
                borderRadius="var(--ggui-shape-radius-lg)"
                style={{ flex: '1 1 280px', minWidth: 0 }}
              >
                <Stack gap="var(--ggui-spacing-4)" align="center" justify="center">
                  <Box
                    padding="var(--ggui-spacing-6)"
                    background="var(--ggui-color-container)"
                    borderRadius="var(--ggui-shape-radius-lg)"
                    style={{ width: '100%', minHeight: '240px', display: 'flex', alignItems: 'center', justifyContent: 'center' }}
                  >
                    <Text variant="bodyLarge" weight="semibold" align="center" color="var(--ggui-color-onContainer)">
                      {props.product.name || 'Product'}
                    </Text>
                  </Box>
                </Stack>
              </Box>

              <Stack gap="var(--ggui-spacing-4)" style={{ flex: '2 1 360px', minWidth: 0 }}>
                <Stack gap="var(--ggui-spacing-2)">
                  <Heading level={2}>{props.product.name || 'Untitled product'}</Heading>
                  <Text variant="bodyLarge" color="var(--ggui-color-primary-700)">
                    {formatCurrency(props.product.price, props.product.currency)}
                  </Text>
                  <Row gap="var(--ggui-spacing-3)" align="center" wrap>
                    <Row gap="var(--ggui-spacing-1)" align="center">
                      {stars.map((star) => (
                        <Icon
                          key={star.key}
                          name="star"
                          size={18}
                          color={star.filled ? 'var(--ggui-color-warning)' : 'var(--ggui-color-outline)'}
                        />
                      ))}
                    </Row>
                    <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                      {toNumber(props.product.rating, 0).toFixed(1)}
                    </Text>
                    <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                      {toNumber(props.product.reviewCount, 0)} reviews
                    </Text>
                  </Row>
                  <Badge variant={isOutOfStock ? 'error' : isLowStock ? 'warning' : 'success'} size="md">
                    {isOutOfStock ? 'Out of Stock' : isLowStock ? 'Low Stock' : 'In Stock'}
                  </Badge>
                </Stack>

                <Text variant="body">{props.product.description || '—'}</Text>
              </Stack>
            </Row>
          </Stack>
        </Card>

        <Card padding="var(--ggui-spacing-6)" shadow="sm">
          <Tabs
            items={tabs}
            activeKey={selectedTab}
            onChange={setSelectedTab}
            variant="line"
          />
        </Card>

        <Card padding="var(--ggui-spacing-6)" shadow="sm">
          <Stack gap="var(--ggui-spacing-4)">
            <Heading level={3}>Purchase</Heading>
            <Row gap="var(--ggui-spacing-4)" align="center" wrap>
              <QuantityControl
                quantity={quantity}
                min={1}
                max={maxQuantity}
                disabled={isOutOfStock}
                onDecrement={() => setQuantity((current) => Math.max(1, current - 1))}
                onIncrement={() => setQuantity((current) => Math.min(maxQuantity, current + 1))}
              />
              <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                Available stock: {stock}
              </Text>
              <Spacer size="flex" />
              <Button variant="primary" size="lg" disabled={isOutOfStock} onClick={handleAddToCart}>
                Add to Cart
              </Button>
            </Row>
          </Stack>
        </Card>
      </Stack>
    </Container>
  );
}

