function formatTimeStamp(value?: string) {
  if (!value) return '';
  const date = new Date(value);
  if (Number.isNaN(date.getTime())) return value;
  return date.toLocaleTimeString([], { hour: 'numeric', minute: '2-digit' });
}

type ChatMessage = {
  id: string;
  sender: string;
  text: string;
  timestamp: string;
  isCurrentUser: boolean;
};

function MessageBubble({ message }: { message: ChatMessage }) {
  return (
    <Box
      padding="var(--ggui-spacing-3)"
      borderRadius="var(--ggui-shape-radius-lg)"
      background={
        message.isCurrentUser
          ? 'var(--ggui-color-primary-600)'
          : 'var(--ggui-color-surfaceVariant)'
      }
      margin="0"
    >
      <Stack gap="var(--ggui-spacing-1)">
        <Text
          variant="label"
          color={message.isCurrentUser ? 'var(--ggui-color-onPrimary)' : 'var(--ggui-color-onSurface)'}
        >
          {message.sender}
        </Text>
        <Text
          variant="body"
          color={message.isCurrentUser ? 'var(--ggui-color-onPrimary)' : 'var(--ggui-color-onSurface)'}
        >
          {message.text}
        </Text>
        <Text
          variant="caption"
          color={message.isCurrentUser ? 'var(--ggui-color-onPrimary)' : 'var(--ggui-color-onSurfaceVariant)'}
        >
          {formatTimeStamp(message.timestamp)}
        </Text>
      </Stack>
    </Box>
  );
}

function groupMessages(messages: ChatMessage[]) {
  const groups: Array<{ sender: string; isCurrentUser: boolean; messages: ChatMessage[] }> = [];
  messages.forEach((message) => {
    const last = groups[groups.length - 1];
    if (last && last.sender === message.sender) {
      last.messages.push(message);
    } else {
      groups.push({ sender: message.sender, isCurrentUser: message.isCurrentUser, messages: [message] });
    }
  });
  return groups;
}

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
  // Actions — fire-and-forget to agent
  const sendMessage = useAction<ActionSendMessagePayload>('sendMessage'); // Called when user sends a message. Payload: { text, timestamp }

  // Streams — real-time from agent (.latest, .all)
  const message = useStream<StreamMessage>('message'); // New message from another participant — append to message list
  const typing = useStream<StreamTyping>('typing'); // Typing indicator — show/hide based on active flag

  const [draft, setDraft] = useState('');
  const [messages, setMessages] = useState<ChatMessage[]>(() =>
    Array.isArray(props.messages)
      ? props.messages.map((msg, index) => ({
          id: `${msg.timestamp ?? 'initial'}-${index}-${msg.sender ?? 'unknown'}`,
          sender: msg.sender ?? 'Unknown',
          text: msg.text ?? '',
          timestamp: msg.timestamp ?? new Date().toISOString(),
          isCurrentUser: (msg.sender ?? '') === props.currentUser,
        }))
      : []
  );
  const bottomRef = useRef<HTMLDivElement | null>(null);
  const typingActive = Boolean(typing.latest?.active && typing.latest?.sender && typing.latest.sender !== props.currentUser);

  useEffect(() => {
    if (message.latest) {
      setMessages((prev) => [
        ...prev,
        {
          id: `${message.latest?.timestamp ?? new Date().toISOString()}-${prev.length}`,
          sender: message.latest.sender ?? 'Unknown',
          text: message.latest.text ?? '',
          timestamp: message.latest.timestamp ?? new Date().toISOString(),
          isCurrentUser: (message.latest.sender ?? '') === props.currentUser,
        },
      ]);
    }
  }, [message.latest, props.currentUser]);

  useEffect(() => {
    bottomRef.current?.scrollIntoView({ behavior: 'smooth', block: 'end' });
  }, [messages.length, typingActive]);

  const groupedMessages = useMemo(() => groupMessages(messages), [messages]);

  const handleSend = useCallback(() => {
    const trimmed = draft.trim();
    if (!trimmed) return;
    const timestamp = new Date().toISOString();
    sendMessage({ text: trimmed, timestamp });
    setMessages((prev) => [
      ...prev,
      {
        id: `local-${timestamp}-${prev.length}`,
        sender: props.currentUser,
        text: trimmed,
        timestamp,
        isCurrentUser: true,
      },
    ]);
    setDraft('');
  }, [draft, props.currentUser, sendMessage]);

  const handleKeyDown = useCallback((event: React.KeyboardEvent<HTMLInputElement>) => {
    if (event.key === 'Enter' && !event.shiftKey) {
      event.preventDefault();
      handleSend();
    }
  }, [handleSend]);

  const participantLabel = props.participantCount === 1 ? '1 participant' : `${props.participantCount} participants`;
  const typingLabel = typingActive ? `${typing.latest?.sender ?? 'Someone'} is typing...` : '';

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Card
        padding="var(--ggui-spacing-0)"
        shadow="md"
        radius="xl"
      >
        <Stack gap="0">
          <Box
            padding="var(--ggui-spacing-4)"
            background="var(--ggui-color-container)"
            borderRadius="var(--ggui-shape-radius-xl) var(--ggui-shape-radius-xl) 0 0"
          >
            <Row align="center" gap="var(--ggui-spacing-3)">
              <Stack gap="var(--ggui-spacing-1)">
                <Heading level={3} color="var(--ggui-color-onContainer)">{props.title}</Heading>
                <Text variant="caption" color="var(--ggui-color-onContainer)">
                  {props.currentUser}
                </Text>
              </Stack>
              <Spacer size="flex" />
              <Badge variant="primary" size="md">{participantLabel}</Badge>
              {typingActive && (
                <Badge variant="success" size="md">
                  {typing.latest?.sender ?? 'Someone'}
                </Badge>
              )}
            </Row>
            {typingLabel && (
              <Text variant="caption" color="var(--ggui-color-onContainer)" style={{ marginTop: 'var(--ggui-spacing-2)' }}>
                {typingLabel}
              </Text>
            )}
          </Box>

          <Box
            padding="var(--ggui-spacing-4)"
            background="var(--ggui-color-surface)"
            style={{ maxHeight: '60vh', overflowY: 'auto' }}
          >
            <Stack gap="var(--ggui-spacing-3)">
              {groupedMessages.length === 0 ? (
                <Text variant="body" color="var(--ggui-color-onSurfaceVariant)">
                  No messages yet. Start the conversation below.
                </Text>
              ) : (
                groupedMessages.map((group, groupIndex) => (
                  <Stack
                    key={`${group.sender}-${groupIndex}`}
                    gap="var(--ggui-spacing-2)"
                    align={group.isCurrentUser ? 'end' : 'start'}
                  >
                    <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                      {group.sender}
                    </Text>
                    <Stack gap="var(--ggui-spacing-2)" align={group.isCurrentUser ? 'end' : 'start'}>
                      {group.messages.map((msg) => (
                        <Box
                          key={msg.id}
                          style={{
                            alignSelf: group.isCurrentUser ? 'flex-end' : 'flex-start',
                            maxWidth: 'min(80%, 48rem)',
                          }}
                        >
                          <MessageBubble message={msg} />
                        </Box>
                      ))}
                    </Stack>
                  </Stack>
                ))
              )}
              <div ref={bottomRef} />
            </Stack>
          </Box>

          <Divider margin="0" />

          <Box padding="var(--ggui-spacing-4)">
            <Stack gap="var(--ggui-spacing-3)">
              <TextArea
                label="Message composer"
                value={draft}
                onChange={setDraft}
                placeholder="Type a message..."
                rows={3}
                autoResize
              />
              <Row justify="between" align="center" gap="var(--ggui-spacing-3)">
                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                  Press Enter to send
                </Text>
                <Button variant="primary" onClick={handleSend} disabled={!draft.trim()}>
                  Send
                </Button>
              </Row>
            </Stack>
          </Box>
        </Stack>
      </Card>
    </Container>
  );
}

