interface Props {
  stocks: Array<{ symbol?: string; name?: string; price?: number; change?: number; changePercent?: number }>; // Array of stocks with symbol, name, price, change, changePercent
}


// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: Updated price data for one or more stocks */
type StreamPriceUpdate = { symbol?: string; price?: number; change?: number; changePercent?: number };

/** Stream event: Market open/closed status update */
type StreamMarketStatus = { status?: 'open' | 'closed' | 'pre-market' | 'after-hours'; timestamp?: string };




function formatCurrency(value: number): string {
  return new Intl.NumberFormat('en-US', {
    minimumFractionDigits: 2,
    maximumFractionDigits: 2,
  }).format(value);
}

function formatSignedNumber(value: number): string {
  const formatted = formatCurrency(Math.abs(value));
  return value >= 0 ? `+${formatted}` : `-${formatted}`;
}

function formatTimestamp(date: Date): string {
  return date.toLocaleTimeString([], {
    hour: 'numeric',
    minute: '2-digit',
    second: '2-digit',
  });
}

function getChangeTone(change: number): 'success' | 'error' | 'default' {
  if (change > 0) return 'success';
  if (change < 0) return 'error';
  return 'default';
}

function getArrow(change: number): string {
  if (change > 0) return '▲';
  if (change < 0) return '▼';
  return '•';
}

function normalizeStock(stock: Props['stocks'][number]) {
  return {
    symbol: stock.symbol ?? '—',
    name: stock.name ?? 'Unknown company',
    price: Number.isFinite(stock.price ?? NaN) ? (stock.price as number) : 0,
    change: Number.isFinite(stock.change ?? NaN) ? (stock.change as number) : 0,
    changePercent: Number.isFinite(stock.changePercent ?? NaN) ? (stock.changePercent as number) : 0,
  };
}

function StockCard({
  stock,
  flashId,
}: {
  stock: { symbol: string; name: string; price: number; change: number; changePercent: number };
  flashId: number;
}) {
  const tone = getChangeTone(stock.change);
  const borderColor = tone === 'success' ? 'var(--ggui-color-success-500)' : tone === 'error' ? 'var(--ggui-color-error-500)' : 'var(--ggui-color-outlineVariant)';
  const textColor = tone === 'success' ? 'var(--ggui-color-success-700)' : tone === 'error' ? 'var(--ggui-color-error-700)' : 'var(--ggui-color-onSurfaceVariant)';
  const flashColor = tone === 'success' ? 'var(--ggui-color-success-100)' : tone === 'error' ? 'var(--ggui-color-error-100)' : 'var(--ggui-color-primary-100)';
  return (
    <Card
      key={`${stock.symbol}-${stock.price}-${flashId}`}
      padding="var(--ggui-spacing-5)"
      shadow="sm"
      radius="lg"
      border
      style={{
        borderColor,
        animation: 'ggui-flash 500ms ease-out',
        '--ggui-flash-color': flashColor,
      } as React.CSSProperties}
    >
      <Stack gap="var(--ggui-spacing-3)">
        <Row justify="between" align="center">
          <Stack gap="var(--ggui-spacing-1)">
            <Text variant="overline" color={textColor}>
              {stock.symbol}
            </Text>
            <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
              {stock.name}
            </Text>
          </Stack>
          <Badge variant={tone} size="sm">
            {tone === 'default' ? 'Flat' : tone === 'success' ? 'Up' : 'Down'}
          </Badge>
        </Row>
        <Heading level={3} color="var(--ggui-color-onSurface)">
          ${formatCurrency(stock.price)}
        </Heading>
        <Row justify="between" align="center">
          <Text variant="body" weight="medium" color={textColor}>
            {formatSignedNumber(stock.change)}
          </Text>
          <Text variant="body" weight="medium" color={textColor}>
            {getArrow(stock.change)} {stock.changePercent >= 0 ? '+' : '-'}{Math.abs(stock.changePercent).toFixed(2)}%
          </Text>
        </Row>
      </Stack>
    </Card>
  );
}

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract

  // Streams — real-time from agent (.latest, .all)
  const priceUpdate = useStream<StreamPriceUpdate>('priceUpdate'); // Updated price data for one or more stocks
  const marketStatus = useStream<StreamMarketStatus>('marketStatus'); // Market open/closed status update
  const [stocks, setStocks] = useState<Array<{ symbol: string; name: string; price: number; change: number; changePercent: number }>>([]);
  const [lastUpdated, setLastUpdated] = useState<Date>(new Date());
  const [marketState, setMarketState] = useState<string>('connected');
  const highlightRef = useRef<Record<string, number>>({});
  const [flashIds, setFlashIds] = useState<Record<string, number>>({});

  useEffect(() => {
    setStocks((props.stocks ?? []).map(normalizeStock));
  }, [props.stocks]);

  useEffect(() => {
    const now = new Date();
    setLastUpdated(now);
  }, []);

  useEffect(() => {
    const interval = setInterval(() => {
      setLastUpdated(new Date());
    }, 1000);
    return () => clearInterval(interval);
  }, []);

  useEffect(() => {
    const updates = priceUpdate.all ?? [];
    if (updates.length === 0) return;

    setStocks((current) => {
      if (!Array.isArray(updates) || updates.length === 0) return current;
      const nextStocks = current.map((stock) => {
        const matches = updates.filter((update) => update?.symbol && update.symbol === stock.symbol);
        if (matches.length === 0) return stock;

        const latest = matches[matches.length - 1];
        highlightRef.current[stock.symbol] = Date.now();
        setFlashIds((prev) => ({ ...prev, [stock.symbol]: (prev[stock.symbol] ?? 0) + 1 }));
        return {
          ...stock,
          price: Number.isFinite(latest?.price ?? NaN) ? (latest?.price as number) : stock.price,
          change: Number.isFinite(latest?.change ?? NaN) ? (latest?.change as number) : stock.change,
          changePercent: Number.isFinite(latest?.changePercent ?? NaN) ? (latest?.changePercent as number) : stock.changePercent,
        };
      });
      return nextStocks;
    });
  }, [priceUpdate.all]);

  useEffect(() => {
    if (marketStatus.latest?.status) {
      setMarketState(`${marketStatus.latest.status}${marketStatus.latest.timestamp ? ` • ${marketStatus.latest.timestamp}` : ''}`);
    }
  }, [marketStatus.latest]);

  const sortedStocks = useMemo(() => {
    return [...stocks].sort((a, b) => a.symbol.localeCompare(b.symbol));
  }, [stocks]);

  const highlightKey = useMemo(() => String(flashIds), [flashIds]);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        <Card padding="var(--ggui-spacing-5)" shadow="sm" radius="lg" border>
          <Row justify="between" align="center" wrap>
            <Stack gap="var(--ggui-spacing-1)">
              <Heading level={2}>Market Watch</Heading>
              <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                {marketState}
              </Text>
            </Stack>
            <Stack align="end" gap="var(--ggui-spacing-1)">
              <Text variant="overline" color="var(--ggui-color-onSurfaceVariant)">
                Last Updated
              </Text>
              <Text variant="body" weight="medium">
                {formatTimestamp(lastUpdated)}
              </Text>
            </Stack>
          </Row>
        </Card>

        <Box
          background="var(--ggui-color-surface)"
          borderRadius="var(--ggui-shape-radius-lg)"
          padding="var(--ggui-spacing-6)"
        >
          <CardGrid columns={{ sm: 1, md: 3, lg: 3 }} gap={16}>
            {sortedStocks.length > 0 ? (
              sortedStocks.map((stock) => (
                <StockCard
                  key={stock.symbol}
                  stock={stock}
                  flashId={flashIds[stock.symbol] ?? 0}
                />
              ))
            ) : (
              <Card padding="var(--ggui-spacing-6)" shadow="sm" border radius="lg">
                <Stack gap="var(--ggui-spacing-2)" align="center">
                  <Spinner />
                  <Text color="var(--ggui-color-onSurfaceVariant)">
                    No stock data available.
                  </Text>
                </Stack>
              </Card>
            )}
          </CardGrid>
        </Box>
      </Stack>
    </Container>
  );
}

