  const avatarOptions = useMemo(() => normalizeAvatarOptions(props.avatarOptions), [props.avatarOptions]);
  const roleOptions = useMemo(() => normalizeRoleOptions(props.roleOptions), [props.roleOptions]);
  const initialAvatar = props.initialProfile.avatar && avatarOptions.includes(props.initialProfile.avatar) ? props.initialProfile.avatar : (avatarOptions[0] ?? AVATAR_OPTIONS_FALLBACK[0]);
  const initialRole = props.initialProfile.role && roleOptions.includes(props.initialProfile.role) ? props.initialProfile.role : (roleOptions[0] ?? ROLE_OPTIONS_FALLBACK[0]);
  const initialTheme = props.initialProfile.theme === 'dark' ? 'dark' : 'light';

  const [step, setStep] = useState(1);
  const [name, setName] = useState(props.initialProfile.name ?? '');
  const [email, setEmail] = useState(props.initialProfile.email ?? '');
  const [avatar, setAvatar] = useState(initialAvatar);
  const [role, setRole] = useState(initialRole);
  const [emailNotifications, setEmailNotifications] = useState(props.initialProfile.emailNotifications ?? true);
  const [theme, setTheme] = useState(initialTheme);
  const [touched, setTouched] = useState({ name: false, email: false });
  const [submitted, setSubmitted] = useState(false);
  const [direction, setDirection] = useState<'forward' | 'backward'>('forward');

  useEffect(() => {
    setName(props.initialProfile.name ?? '');
    setEmail(props.initialProfile.email ?? '');
    setAvatar(props.initialProfile.avatar && avatarOptions.includes(props.initialProfile.avatar) ? props.initialProfile.avatar : (avatarOptions[0] ?? AVATAR_OPTIONS_FALLBACK[0]));
    setRole(props.initialProfile.role && roleOptions.includes(props.initialProfile.role) ? props.initialProfile.role : (roleOptions[0] ?? ROLE_OPTIONS_FALLBACK[0]));
    setEmailNotifications(props.initialProfile.emailNotifications ?? true);
    setTheme(props.initialProfile.theme === 'dark' ? 'dark' : 'light');
    setStep(1);
    setTouched({ name: false, email: false });
    setSubmitted(false);
  }, [props.initialProfile, avatarOptions, roleOptions]);

  const nameError = touched.name && !name.trim() ? 'Name is required.' : '';
  const emailError = touched.email && !email.trim() ? 'Email is required.' : touched.email && email.trim() && !isValidEmail(email) ? 'Enter a valid email address.' : '';
  const canGoNext = useMemo(() => {
    if (step === 1) {
      return Boolean(name.trim()) && Boolean(email.trim()) && isValidEmail(email);
    }
    return true;
  }, [name, email, step]);
  const progress = step === 1 ? 33 : step === 2 ? 66 : 100;
  const stepAnimation = direction === 'forward' ? 'ggui-slideInUp 200ms ease-out both' : 'ggui-slideInDown 200ms ease-out both';

  const goNext = useCallback(() => {
    if (step === 1) {
      setTouched({ name: true, email: true });
      if (!canGoNext) return;
      setDirection('forward');
      setStep(2);
      return;
    }
    if (step === 2) {
      setDirection('forward');
      setStep(3);
    }
  }, [canGoNext, step]);

  const goBack = useCallback(() => {
    setDirection('backward');
    setStep((current) => Math.max(1, current - 1));
  }, []);

  const handleComplete = useCallback(() => {
    const payload = {
      name: name.trim(),
      email: email.trim(),
      avatar,
      role,
      emailNotifications,
      theme,
    };
    setSubmitted(true);
    complete(payload);
  }, [name, email, avatar, role, emailNotifications, theme, complete]);

  const summaryRows = useMemo(() => ([
    { label: 'Name', value: name.trim() || '—' },
    { label: 'Email', value: email.trim() || '—' },
    { label: 'Avatar', value: avatar },
    { label: 'Role', value: role || '—' },
    { label: 'Email notifications', value: emailNotifications ? 'On' : 'Off' },
    { label: 'Theme', value: theme === 'dark' ? 'Dark' : 'Light' },
  ]), [name, email, avatar, role, emailNotifications, theme]);


    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">

        <Card padding="var(--ggui-spacing-6)" shadow="md" radius="xl">
          <Stack gap="var(--ggui-spacing-4)">
            <Stack gap="var(--ggui-spacing-2)">
              <Row align="center" justify="between">
                <Stack gap="var(--ggui-spacing-1)">
                  <Heading level={2}>Onboarding wizard</Heading>
                  <Text color="var(--ggui-color-onSurfaceVariant)">Complete your profile in 3 simple steps.</Text>
                </Stack>
                <Badge variant={submitted ? 'success' : 'primary'}>{submitted ? 'Saved' : 'In progress'}</Badge>
              </Row>
              <Stack gap="var(--ggui-spacing-2)">
                <Row align="center" justify="between">
                  <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">Step {step} of 3</Text>
                  <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">{progress}%</Text>
                </Row>
                <Progress value={progress} max={100} size="md" />
              </Stack>
            </Stack>

            <Stack gap="var(--ggui-spacing-3)">
              <Row gap="var(--ggui-spacing-2)" wrap>
                <Stack gap="var(--ggui-spacing-2)" align="center">
                  <StepCircle step={1} current={step === 1} completed={step > 1} />
                  <Text variant="label">Profile Setup</Text>
                </Stack>
                <Stack gap="var(--ggui-spacing-2)" align="center">
                  <StepCircle step={2} current={step === 2} completed={step > 2} />
                  <Text variant="label">Preferences</Text>
                </Stack>
                <Stack gap="var(--ggui-spacing-2)" align="center">
                  <StepCircle step={3} current={step === 3} completed={step > 3} />
                  <Text variant="label">Review & Confirm</Text>
                </Stack>
              </Row>
            </Stack>
          </Stack>
        </Card>

        <Card padding="var(--ggui-spacing-6)" shadow="lg" radius="xl">
          <Box
            style={{ animation: stepAnimation, transition: 'opacity 200ms ease, transform 200ms ease' }}
          >
            {step === 1 && (
              <Stack gap="var(--ggui-spacing-5)">
                <Stack gap="var(--ggui-spacing-2)">
                  <Heading level={3}>Profile Setup</Heading>
                  <Text color="var(--ggui-color-onSurfaceVariant)">Tell us how you’d like to be addressed.</Text>
                </Stack>
                <Stack gap="var(--ggui-spacing-4)">
                  <Input label="Name" value={name} onChange={(value) => setName(value)} required placeholder="Jane Doe" error={nameError || undefined} />
                  <Input label="Email" type="email" value={email} onChange={(value) => setEmail(value)} required placeholder="jane@example.com" error={emailError || undefined} />
                  <Stack gap="var(--ggui-spacing-2)">
                    <Text variant="label" is="div">Avatar</Text>
                    <Row gap="var(--ggui-spacing-2)" wrap>
                      {avatarOptions.map((item) => (
                        <AvatarChoice key={item} emoji={item} selected={avatar === item} onSelect={() => setAvatar(item)} />
                      ))}
                    </Row>
                  </Stack>
                </Stack>
              </Stack>
            )}

            {step === 2 && (
              <Stack gap="var(--ggui-spacing-5)">
                <Stack gap="var(--ggui-spacing-2)">
                  <Heading level={3}>Preferences</Heading>
                  <Text color="var(--ggui-color-onSurfaceVariant)">Choose defaults for your workspace experience.</Text>
                </Stack>
                <Stack gap="var(--ggui-spacing-4)">
                  <Select label="Role" value={role} onChange={setRole} options={roleOptions.map((item) => ({ value: item, label: item }))} />
                  <Checkbox label="Email notifications" checked={emailNotifications} onChange={setEmailNotifications} description="Receive updates and reminders by email." />
                  <Row align="center" justify="between">
                    <Stack gap="var(--ggui-spacing-1)">
                      <Text variant="label">Theme preference</Text>
                      <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">Switch between light and dark mode.</Text>
                    </Stack>
                    <Toggle label="Theme preference" checked={theme === 'dark'} onChange={(checked) => setTheme(checked ? 'dark' : 'light')} size="md" />
                  </Row>
                </Stack>
              </Stack>
            )}

            {step === 3 && (
              <Stack gap="var(--ggui-spacing-5)">
                <Stack gap="var(--ggui-spacing-2)">
                  <Heading level={3}>Review & Confirm</Heading>
                  <Text color="var(--ggui-color-onSurfaceVariant)">Review everything before completing setup.</Text>
                </Stack>
                <Card padding="var(--ggui-spacing-4)" shadow="sm" radius="lg" border>
                  <Stack gap="var(--ggui-spacing-3)">
                    <Row gap="var(--ggui-spacing-3)" align="center">
                      <Avatar name={name.trim() || 'Avatar'} size="lg" shape="circle" />
                      <Stack gap="var(--ggui-spacing-1)">
                        <Heading level={4}>{name.trim() || 'Unnamed profile'}</Heading>
                        <Text color="var(--ggui-color-onSurfaceVariant)">{email.trim() || 'No email provided'}</Text>
                      </Stack>
                    </Row>
                    <Divider margin="var(--ggui-spacing-2)" />
                    <Stack gap="var(--ggui-spacing-2)">
                      {summaryRows.map((row) => (
                        <Row key={row.label} justify="between" gap="var(--ggui-spacing-3)">
                          <Text color="var(--ggui-color-onSurfaceVariant)">{row.label}</Text>
                          <Text weight="medium">{row.value}</Text>
                        </Row>
                      ))}
                    </Stack>
                    <Row justify="start">
                      <Button variant="ghost" onClick={goBack}>Go Back</Button>
                    </Row>
                  </Stack>
                </Card>
              </Stack>
            )}
          </Box>

          <Divider margin="var(--ggui-spacing-5)" />

          <Row justify="between" align="center" gap="var(--ggui-spacing-3)">
            <Button variant="outline" onClick={goBack} disabled={step === 1}>Go Back</Button>
            <Spacer size="flex" />
            {step < 3 ? (
              <Button variant="primary" onClick={goNext} disabled={!canGoNext}>Next</Button>
            ) : (
              <Button variant="primary" onClick={handleComplete}>Complete Setup</Button>
            )}
          </Row>
        </Card>
      </Stack>
    </Container>
  );
}
